const Command = use('laranode/Console/Command');
const fs = require('fs');
const path = require('path');

class ConfigCacheCommand extends Command {
    constructor(app) {
        super();
        this.app = app;
        this.signature = 'config:cache';
        this.description = 'Create a cache file for faster configuration loading';
    }

    async handle() {
        const configPath = base_path('config');
        const cacheDir = base_path('bootstrap/cache');
        const cacheFile = path.join(cacheDir, 'config.js');
        const jsonCacheFile = path.join(cacheDir, 'config.json');

        if (!fs.existsSync(cacheDir)) {
            fs.mkdirSync(cacheDir, { recursive: true });
        }

        const files = fs.readdirSync(configPath);

        this.info('Configuration caching started...');

        let content = '/**\n * LaraNode Configuration Cache\n * Generated by Artisan config:cache\n */\n\n';
        content += 'module.exports = {\n';

        for (const file of files) {
            if (file.endsWith('.js')) {
                const key = file.replace('.js', '');
                const filePath = path.join(configPath, file).replace(/\\/g, '/'); // Normalize path
                content += `    '${key}': require('${filePath}'),\n`;
            }
        }

        content += '};\n';

        try {
            // Remove old JSON cache if it exists to avoid confusion
            if (fs.existsSync(jsonCacheFile)) {
                fs.unlinkSync(jsonCacheFile);
            }

            fs.writeFileSync(cacheFile, content);
            this.info('Configuration cached successfully in [bootstrap/cache/config.js]!');
        } catch (e) {
            this.error(`Failed to write configuration cache: ${e.message}`);
        }
    }
}

module.exports = ConfigCacheCommand;
